(()=>{'use strict';
const $=s=>document.querySelector(s),$$=s=>[...document.querySelectorAll(s)];
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,'').replace(/[^0-9.\-]/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH');
const B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const E=s=>T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
function parseIso(s){const t=T(s);if(!/^\d{4}-\d{2}-\d{2}$/.test(t))return null;const d=new Date(t+'T00:00:00+07:00');return isNaN(d)?null:d}
function thaiDate(d){return d?d.toLocaleDateString('th-TH',{timeZone:'Asia/Bangkok',day:'numeric',month:'long',year:'numeric'}):'-'}
function prevDay(d){const x=new Date(d.getTime());x.setDate(x.getDate()-1);return x}
function selectedReceiver(){let s=T($('#sendText')?.textContent);s=s.replace(/^ส่งให้ร้าน:\s*/,'').trim();if(!s||s==='ยังไม่เลือก'||/^เลือก\s+\d+/.test(s))return'';return s}
function singlePs(){let s=T($('#psText')?.textContent).replace(/^PS:\s*/,'').trim();if(!s||s==='ทั้งหมด'||/^เลือก\s+\d+/.test(s))return'';return s}
function selectedDate(){let s=T($('#datesText')?.textContent).replace(/^วันที่:\s*/,'').trim();if(!s||s==='ทั้งหมด'||s==='ทุกวัน'||/^เลือก\s+\d+/.test(s))return'';const m=s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);if(m){let y=Number(m[3]);if(y>2400)y-=543;return `${y}-${String(m[2]).padStart(2,'0')}-${String(m[1]).padStart(2,'0')}`}return s}
function rowsForReceipt(){const store=selectedReceiver();if(!store)return[];let rows=(window.__doitCoreRows||[]).filter(r=>!r.isTele&&T(r.store)===store);const ps=singlePs();if(ps)rows=rows.filter(r=>T(r.ps)===ps);const d=selectedDate();if(d)rows=rows.filter(r=>T(r.date)===d);return rows}
function groupRows(rows){const m=new Map();rows.forEach(r=>{const k=[r.code||'',r.sku||'',r.type||''].join('|');let g=m.get(k);if(!g){g={code:T(r.code),sku:T(r.sku)||'ไม่ระบุสินค้า',qty:0,amt:0,unit:0,dates:new Set(),ps:new Set()};m.set(k,g)}g.qty+=N(r.qty);g.amt+=N(r.amt);g.unit=g.qty?g.amt/g.qty:N(r.unit);if(r.date)g.dates.add(r.date);if(r.ps)g.ps.add(r.ps)});return[...m.values()].sort((a,b)=>a.sku.localeCompare(b.sku,'th'))}
function workDateFrom(rows){const d=selectedDate()||[...new Set(rows.map(r=>r.date).filter(Boolean))].sort()[0];return parseIso(d)||new Date()}
function psFrom(rows){const p=singlePs()||[...new Set(rows.map(r=>r.ps).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'th')).join(', ');return p||'-'}
function recalc(ov){let tq=0,ta=0;ov.querySelectorAll('tr[data-line]').forEach(tr=>{const q=N(tr.querySelector('.rq')?.textContent);const u=N(tr.querySelector('.ru')?.textContent);const t=q*u;tq+=q;ta+=t;const rt=tr.querySelector('.rt');if(rt)rt.textContent=B(t)});const q=ov.querySelector('#receiptTotalQty');if(q)q.textContent=F(tq);const a=ov.querySelector('#receiptTotalAmt');if(a)a.textContent=B(ta);const h=ov.querySelector('#receiptHeaderTotal');if(h)h.textContent=B(ta)+' บาท'}
function buildReceipt(){const store=selectedReceiver();if(!store){alert('กรุณาเลือก “ส่งให้ร้าน” 1 ร้านก่อน');return}const raw=rowsForReceipt();const p=groupRows(raw);if(!p.length){alert('ไม่มีข้อมูลใบส่งร้านจริงของร้านที่เลือก');return}const work=workDateFrom(raw),sale=prevDay(work),delivery=new Date(),ps=psFrom(raw),docNo='DOIT-'+Date.now().toString().slice(-8);const totalQty=p.reduce((s,g)=>s+N(g.qty),0),totalAmt=p.reduce((s,g)=>s+N(g.amt),0);const style='<style>.receiptPage{font-family:system-ui,-apple-system,"Segoe UI",Tahoma,sans-serif;color:#111;width:194mm;min-height:281mm;margin:8px auto;padding:10mm;background:#fff}.receiptTop{display:flex;justify-content:space-between;gap:16px;border-bottom:3px solid #111;padding-bottom:10px;margin-bottom:12px}.receiptTitle{font-size:24px;font-weight:950;margin:0}.docBox{text-align:right;font-size:12px;line-height:1.7}.metaGrid{display:grid;grid-template-columns:1fr 1fr;gap:8px 16px;border:1px solid #111;padding:8px;margin-bottom:12px}.metaGrid div{font-size:13px}.metaGrid b{display:inline-block;min-width:76px}.receiptTable{width:100%;border-collapse:collapse;font-size:12px}.receiptTable th{background:#f3f4f6}.receiptTable th,.receiptTable td{border:1px solid #111;padding:5px;vertical-align:top}.r{text-align:right}.c{text-align:center}.totalRow td{font-weight:950;background:#f9fafb}.noteBox{border:1px solid #9ca3af;padding:8px;margin-top:12px;min-height:38px;font-size:12px}.signGrid{display:grid;grid-template-columns:1fr 1fr;gap:40px;margin-top:32px}.signBox{text-align:center;border-top:1px solid #111;padding-top:8px;font-size:13px}[contenteditable="true"]{outline:1px dashed transparent;cursor:text}[contenteditable="true"]:focus{outline:1px dashed #2563eb;background:#eff6ff}@media print{.printBar{display:none!important}.receiptPage{width:auto;min-height:auto;margin:0;padding:0}.receiptTable th{background:#eee!important;-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style>';
const body=p.map((g,i)=>'<tr data-line><td class="c">'+(i+1)+'</td><td contenteditable="true">'+E(g.code||'')+'</td><td contenteditable="true">'+E(g.sku)+'</td><td class="r rq" contenteditable="true">'+F(g.qty)+'</td><td class="r ru" contenteditable="true">'+B(g.unit)+'</td><td class="r rt">'+B(g.amt)+'</td></tr>').join('');
const ov=document.createElement('div');ov.className='printOverlay';ov.innerHTML=style+'<div class="printBar"><b>ตรวจ/แก้ไขข้อความในใบเสร็จก่อนปริ้น</b><span><button onclick="this.closest(\'.printOverlay\').remove()">ปิด</button> <button onclick="window.print()">ปริ้น</button></span></div><section class="printPage receiptPage"><div class="receiptTop"><div><h1 class="receiptTitle" contenteditable="true">ใบส่งสินค้า / ใบเสร็จรับเงิน</h1></div><div class="docBox"><div contenteditable="true"><b>เลขที่เอกสาร:</b> '+E(docNo)+'</div></div></div><div class="metaGrid"><div contenteditable="true"><b>ชื่อร้าน:</b> '+E(store)+'</div><div contenteditable="true"><b>รหัส PS:</b> '+E(ps)+'</div><div contenteditable="true"><b>วันที่ขาย:</b> '+E(thaiDate(sale))+'</div><div contenteditable="true"><b>วันที่ส่ง:</b> '+E(thaiDate(delivery))+'</div><div contenteditable="true"><b>ราคารวม:</b> <span id="receiptHeaderTotal">'+E(B(totalAmt))+' บาท</span></div></div><table class="receiptTable"><thead><tr><th style="width:36px">#</th><th style="width:86px">รหัส</th><th>รายการสินค้า</th><th style="width:72px">จำนวน</th><th style="width:92px">ราคา/หน่วย</th><th style="width:100px">รวมเงิน</th></tr></thead><tbody>'+body+'<tr class="totalRow"><td colspan="3" class="r" contenteditable="true">รวมทั้งหมด</td><td class="r" id="receiptTotalQty">'+F(totalQty)+'</td><td></td><td class="r" id="receiptTotalAmt">'+B(totalAmt)+'</td></tr></tbody></table><div class="noteBox" contenteditable="true">หมายเหตุ: </div><div class="signGrid"><div class="signBox" contenteditable="true">ผู้ส่งสินค้า / ผู้จัดทำ</div><div class="signBox" contenteditable="true">ผู้รับสินค้า</div></div></section>';document.body.appendChild(ov);ov.addEventListener('input',e=>{if(e.target.closest('.receiptTable'))recalc(ov)});ov.addEventListener('blur',e=>{if(e.target.closest('.receiptTable'))recalc(ov)},true);recalc(ov)}
function patchPickTable(){const tbl=$('#table');if(!tbl)return;const ths=[...tbl.querySelectorAll('thead th')];if(!ths.length)return;const labels=ths.map(th=>T(th.textContent));const qtyIdx=labels.indexOf('จำนวนรวม');const remIdx=labels.indexOf('คงเหลือ');if(qtyIdx<0||remIdx<0)return;tbl.querySelectorAll('tr').forEach(tr=>{const cells=[...tr.children];if(cells.length<=Math.max(qtyIdx,remIdx)){const cs=tr.querySelector('[colspan]');if(cs&&N(cs.getAttribute('colspan'))>=8)cs.setAttribute('colspan','7');return}const qty=cells[qtyIdx],rem=cells[remIdx];tr.insertBefore(rem,qty);qty.remove()});tbl.style.minWidth='560px'}
let patchBusy=false;function schedulePatch(){if(patchBusy)return;patchBusy=true;requestAnimationFrame(()=>{patchBusy=false;patchPickTable()})}
function installTablePatch(){if($('#corePickTablePatchCss'))return;const st=document.createElement('style');st.id='corePickTablePatchCss';st.textContent='.tbl{min-width:560px!important}@media(max-width:720px){.tbl{min-width:540px!important}.tbl input.pick{width:54px!important}}';document.head.appendChild(st);const target=$('#table');if(target)new MutationObserver(schedulePatch).observe(target,{childList:true,subtree:true});setInterval(schedulePatch,500);schedulePatch()}
function bind(){const b=$('#prepPrint');if(!b)return false;b.onclick=buildReceipt;installTablePatch();return true}
function boot(){if(!bind())setTimeout(boot,300)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();